import { IApiResponse, IPaginatedResponse, QueryFilter } from '@common/interfaces/response.interface';
import OKRsModel from './okrs.model';
import { ApiError } from '@common/utils/ApiError';
import { PipelineStage, Types } from 'mongoose';
import { IOKRFilter, IOKRPayload, IOKRRankingFilter, IOKRs, IOKREmployeeResponse } from '@common/interfaces/okrs.interface';
import { IUserContext } from '@common/helpers/permission.helper';
import { UserRoleDefined } from '@common/utils/enum';
import EmployeesModel from '@modules/employees/employees.model';
import { IEmployees } from '@common/interfaces/employee.interface';
import moment from 'moment-timezone';

export class OKRService {
    public async createOKR(payload: IOKRPayload, userContext: IUserContext): Promise<IApiResponse<IOKRs>> {
        if (userContext && userContext.roles === UserRoleDefined.User) {
            if (String(payload.employeeId) !== String(userContext.user?.employeeId)) {
                throw new ApiError(403, 'Bạn không có quyền tạo OKR cho người khác');
            }
        }

        const isExist = await OKRsModel.findOne({
            employeeId: payload.employeeId,
            quarter: Number(payload.quarter),
            year: Number(payload.year),
        });

        if (isExist) {
            throw new ApiError(400, 'OKR cho quý này đã tồn tại');
        }

        const okr = await OKRsModel.create(payload);
        return {
            success: true,
            message: 'Tạo OKR thành công',
            data: okr as unknown as IOKRs,
        };
    }

    public async getOKRById(id: string): Promise<IApiResponse<IOKRs>> {
        const okr = await OKRsModel.findById(id);
        if (!okr) {
            throw new ApiError(404, 'Không tìm thấy OKR');
        }
        return {
            success: true,
            message: 'Lấy OKR thành công',
            data: okr as unknown as IOKRs,
        };
    }

    public async updateOKR(id: string, payload: IOKRPayload, userContext: IUserContext): Promise<IApiResponse<IOKRs>> {
        const okrRecord = await OKRsModel.findById(id);
        if (!okrRecord) {
            throw new ApiError(404, 'Không tìm thấy OKR');
        }
        if (userContext && userContext.roles === UserRoleDefined.User) {
            if (String(okrRecord.employeeId) !== String(userContext.user?.employeeId)) {
                throw new ApiError(403, 'Bạn không có quyền chỉnh sửa OKR của người khác');
            }
        }
        const okr = await OKRsModel.findByIdAndUpdate(id, payload, { new: true });
        return {
            success: true,
            message: 'Cập nhật OKR thành công',
            data: okr as unknown as IOKRs,
        };
    }

    public async getOKRByFilter(
        filter: IOKRFilter
    ): Promise<IPaginatedResponse<IOKREmployeeResponse>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;

        const employeeQuery: QueryFilter<IEmployees> = {};

        if (filter.name) {
            employeeQuery.fullName = { $regex: filter.name, $options: 'i' };
        }

        if (filter.departmentId) {
            employeeQuery.departmentId = new Types.ObjectId(
                String(filter.departmentId)
            ) as unknown as string;
        }

        if (filter.employeeId) {
            employeeQuery._id = new Types.ObjectId(
                String(filter.employeeId)
            ) as unknown as string;
        }

        const aggregateQuery: PipelineStage[] = [
            { $match: employeeQuery },

            // join OKR
            {
                $lookup: {
                    from: 'okrs',
                    let: { empId: '$_id' },
                    pipeline: [
                        {
                            $match: {
                                $expr: {
                                    $eq: ['$employeeId', '$$empId'],
                                },
                                ...(filter.year && { year: Number(filter.year) }),
                                ...(filter.quarter && {
                                    quarter: Number(filter.quarter),
                                }),
                                ...(filter.status && { status: filter.status }),
                            },
                        },
                    ],
                    as: 'okrData',
                },
            },

            { $addFields: { okr: { $arrayElemAt: ['$okrData', 0] } } },

            // join Objective
            {
                $lookup: {
                    from: 'objectives',
                    localField: 'okr._id',
                    foreignField: 'okrId',
                    as: 'objectives',
                },
            },

            // join KeyResult
            {
                $lookup: {
                    from: 'key-results',
                    localField: 'objectives._id',
                    foreignField: 'objectiveId',
                    as: 'keyResults',
                },
            },

            // join KeyResultScore
            {
                $lookup: {
                    from: 'key-result-scores',
                    localField: 'keyResults._id',
                    foreignField: 'keyResultId',
                    as: 'keyResultScores',
                },
            },

            // TÍNH averageScore 
            {
                $addFields: {
                    okr: {
                        $cond: [
                            { $ifNull: ['$okr', false] }, // nếu có OKR
                            {
                                $mergeObjects: [
                                    '$okr',
                                    {
                                        averageScore: {
                                            $cond: [
                                                { $gt: [{ $size: '$keyResults' }, 0] },
                                                {
                                                    $avg: {
                                                        $map: {
                                                            input: '$keyResults',
                                                            as: 'kr',
                                                            in: {
                                                                $let: {
                                                                    vars: {
                                                                        scores: {
                                                                            $filter: {
                                                                                input: '$keyResultScores',
                                                                                as: 's',
                                                                                cond: {
                                                                                    $eq: ['$$s.keyResultId', '$$kr._id'],
                                                                                },
                                                                            },
                                                                        },
                                                                    },
                                                                    in: {
                                                                        $let: {
                                                                            vars: {
                                                                                resultScore: {
                                                                                    $first: {
                                                                                        $filter: {
                                                                                            input: '$$scores',
                                                                                            as: 'rs',
                                                                                            cond: {
                                                                                                $eq: ['$$rs.week', 'result'],
                                                                                            },
                                                                                        },
                                                                                    },
                                                                                },
                                                                                maxWeek: {
                                                                                    $max: {
                                                                                        $map: {
                                                                                            input: {
                                                                                                $filter: {
                                                                                                    input: '$$scores',
                                                                                                    as: 's2',
                                                                                                    cond: { $isNumber: '$$s2.week' },
                                                                                                },
                                                                                            },
                                                                                            as: 'w',
                                                                                            in: '$$w.week',
                                                                                        },
                                                                                    },
                                                                                },
                                                                            },
                                                                            in: {
                                                                                $cond: [
                                                                                    { $ifNull: ['$$resultScore.score', false] },
                                                                                    '$$resultScore.score',
                                                                                    {
                                                                                        $let: {
                                                                                            vars: {
                                                                                                latestScore: {
                                                                                                    $first: {
                                                                                                        $filter: {
                                                                                                            input: '$$scores',
                                                                                                            as: 's3',
                                                                                                            cond: {
                                                                                                                $eq: ['$$s3.week', '$$maxWeek'],
                                                                                                            },
                                                                                                        },
                                                                                                    },
                                                                                                },
                                                                                            },
                                                                                            in: {
                                                                                                $ifNull: ['$$latestScore.score', 0],
                                                                                            },
                                                                                        },
                                                                                    },
                                                                                ],
                                                                            },
                                                                        },
                                                                    },
                                                                },
                                                            },
                                                        },
                                                    },
                                                },
                                                0,
                                            ],
                                        },
                                    },
                                ],
                            },
                            null, // nếu không có OKR → trả null luôn
                        ],
                    },
                },
            },

            {
                $project: {
                    _id: 1,
                    fullName: 1,
                    code: 1,
                    avatar: 1,
                    departmentId: 1,
                    okr: 1,
                },
            },

            { $sort: { fullName: 1 } },
        ];

        const [employees, totalEmployees] = await Promise.all([
            EmployeesModel.aggregate(aggregateQuery)
                .skip((page - 1) * limit)
                .limit(limit),
            EmployeesModel.countDocuments(employeeQuery),
        ]);

        return {
            success: true,
            data: employees,
            meta: {
                totalItems: totalEmployees,
                itemCount: employees.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(totalEmployees / limit),
                currentPage: page,
            },
        };
    }

    public async deleteOKR(id: string, userContext: IUserContext): Promise<IApiResponse<null>> {
        const okrRecord = await OKRsModel.findById(id);
        if (!okrRecord) {
            throw new ApiError(404, 'Không tìm thấy OKR');
        }
        if (userContext && userContext.roles === UserRoleDefined.User) {
            if (String(okrRecord.employeeId) !== String(userContext.user?.employeeId)) {
                throw new ApiError(403, 'Bạn không có quyền xóa OKR của người khác');
            }
        }
        await OKRsModel.findByIdAndDelete(id);
        return {
            success: true,
            message: 'Xóa OKR thành công',
            data: null,
        };
    }

    public async avgKeyResultByOKR(filter: IOKRRankingFilter): Promise<IApiResponse<unknown[]>> {
        const { quarter, year, departmentId } = filter;
        const match: QueryFilter<IOKRs> = {};
        if (quarter) match.quarter = Number(quarter);
        if (year) match.year = Number(year);

        const aggregateQuery: PipelineStage[] = [
            { $match: match },
            {
                $lookup: {
                    from: 'employees',
                    localField: 'employeeId',
                    foreignField: '_id',
                    as: 'employee',
                },
            },
            { $unwind: '$employee' },
        ];

        if (departmentId) {
            aggregateQuery.push({
                $match: { 'employee.departmentId': new Types.ObjectId(String(departmentId)) },
            });
        }

        const okrs = await OKRsModel.aggregate(aggregateQuery);

        const ranking = okrs
            .map((okr) => {
                let averageScore = 0;
                if (okr.keyResults && okr.keyResults.length > 0) {
                    const sum = okr.keyResults.reduce((acc: number, kr: { score?: number }) => acc + (kr.score || 0), 0);
                    averageScore = sum / okr.keyResults.length;
                }
                return {
                    employeeId: okr.employeeId,
                    fullName: okr.employee.fullName,
                    code: okr.employee.code,
                    averageScore: parseFloat(averageScore.toFixed(2)),
                };
            })
            .sort((a, b) => b.averageScore - a.averageScore);

        return {
            success: true,
            message: 'Lấy xếp hạng OKR thành công',
            data: ranking,
        };
    }

    public getTimeOfViewOKR(): { weekScore: number; quarter: number; year: number } {
        const now = moment().tz('Asia/Ho_Chi_Minh');
        const year = now.year();
        const quarter = now.quarter();
        const startOfQuarter = moment().tz('Asia/Ho_Chi_Minh').quarter(quarter).startOf('quarter');
        const weekScore = now.diff(startOfQuarter, 'weeks') + 1;

        return {
            weekScore,
            quarter,
            year,
        };
    }
}

