import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import SystemLogModel from './systemLog.model';
import { ApiError } from '@common/utils/ApiError';
import { PipelineStage } from 'mongoose';
import { ISystemLogs, ISystemLogsFilter, ISystemLogsPayload } from '@common/interfaces/systemLog.interface';

export class SystemLogService {
    public async createSystemLog(payload: ISystemLogsPayload): Promise<IApiResponse<ISystemLogs>> {
        const newDepartment = await SystemLogModel.create(payload);
        return {
            success: true,
            message: 'Tạo lịch chấm công thành công',
            data: newDepartment,
        };
    }

    public async getSystemLogsByFilter(filter: ISystemLogsFilter): Promise<IPaginatedResponse<ISystemLogs>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const aggregateQuery: PipelineStage[] = [
            { $sort: { createdAt: -1 } },
            { $skip: (page - 1) * limit },
            { $limit: limit },
        ];

        const [records, docCounter] = await Promise.all([
            SystemLogModel.aggregate(aggregateQuery),
            SystemLogModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách lịch chấm công thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getSystemLogById(id: string): Promise<IApiResponse<ISystemLogs>> {
        const record = await SystemLogModel.findById(id);
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy lịch chấm công này');
        }
        return {
            success: true,
            message: 'Đã thấy lịch chấm công',
            data: record,
        };
    }

    public async updateSystemLog(id: string, payload: ISystemLogsPayload): Promise<IApiResponse<ISystemLogs>> {
        const schedules = await SystemLogModel.findByIdAndUpdate(id, payload);
        if (!schedules) {
            throw new ApiError(404, 'Loại khấu trừ không tồn tại');
        }
        return {
            success: true,
            message: 'Cập nhật thông tin lịch chấm công thành công',
            data: schedules,
        };
    }

    public async deleteSystemLog(id: string): Promise<IApiResponse<ISystemLogs>> {
        const schedules = await SystemLogModel.findByIdAndDelete(id);
        if (!schedules) {
            throw new ApiError(404, 'Loại khấu trừ không tồn tại');
        }
        return {
            success: true,
            message: 'Xóa lịch chấm công thành công',
            data: schedules,
        };
    }
}

