import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import NikoCriteriaModel from './nikoCriteria.model';
import { INikoCriteria, INikoCriteriaFilter, INikoCriteriaPayload } from '@common/interfaces/nikoCriteria.interface';
import mongoose, { PipelineStage, QueryFilter } from 'mongoose';

export class NikoCriteriaService {
    public async createNikoCriteria(payload: INikoCriteriaPayload): Promise<IApiResponse<INikoCriteria>> {
        const existed = await NikoCriteriaModel.findOne({ name: payload.name });
        if (payload.sectorIds && payload.sectorIds.length > 0 && existed?.sectorIds) {
            const existedSectorIds = existed.sectorIds.map((f) => f.toString());
            const hasOverlap = payload.sectorIds.some((f) => existedSectorIds.includes(f.toString()));
            if (hasOverlap) {
                throw new ApiError(400, 'Tên tiêu chí đã tồn tại trong lĩnh vực này');
            }
        }

        try {
            const result = await NikoCriteriaModel.create(payload);
            return {
                success: true,
                message: 'Thêm tiêu chí thành công',
                data: result,
            };
        } catch {
            throw new ApiError(500, 'Thêm thất bại, vui lòng thử lại');
        }
    }

    public async getNikoCriteriaById(id: string): Promise<IApiResponse<INikoCriteria>> {
        const result = await NikoCriteriaModel.findById(id).populate('sectorIds');
        if (!result) {
            throw new ApiError(404, 'Không tìm thấy tiêu chí');
        }
        return {
            success: true,
            message: 'Lấy tiêu chí thành công',
            data: result,
        };
    }

    public async getNikoCriteriaByFilter(filter: INikoCriteriaFilter): Promise<IPaginatedResponse<INikoCriteria>> {
        const limit = Number(filter.limit) || 10;
        const page = Number(filter.page) || 1;
        const query: QueryFilter<INikoCriteriaFilter> = {};

        if (filter.name) {
            query.name = {
                $regex: `.*${filter.name}.*`,
                $options: 'i',
            };
        }

        if (filter.status) {
            query.status = filter.status;
        }

        const aggregateQuery: PipelineStage[] = [{ $match: query }, { $sort: { createdAt: -1 } }];

        const [records, docCounter] = await Promise.all([
            NikoCriteriaModel.aggregate([
                ...aggregateQuery,
                { $skip: (page - 1) * limit },
                { $limit: limit },
                {
                    $lookup: {
                        from: 'niko-sectors',
                        localField: 'sectorIds',
                        foreignField: '_id',
                        as: 'sectors',
                    },
                },
            ]),
            NikoCriteriaModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);

        const count = docCounter[0]?.count || 0;
        return {
            data: records,
            success: true,
            message: 'Lấy danh sách tiêu chí thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async updateNikoCriteria(id: string, payload: INikoCriteriaPayload): Promise<IApiResponse<INikoCriteria>> {
        if (payload.name) {
            const existed = await NikoCriteriaModel.findOne({ name: payload.name, _id: { $ne: id } });
            if (payload.sectorIds && payload.sectorIds.length > 0 && existed?.sectorIds) {
                const existedSectorIds = existed.sectorIds.map((f) => f.toString());
                const hasOverlap = payload.sectorIds.some((f) => existedSectorIds.includes(f.toString()));
                if (hasOverlap) {
                    throw new ApiError(400, 'Tên tiêu chí đã tồn tại trong lĩnh vực này');
                }
            }
        }

        const result = await NikoCriteriaModel.findByIdAndUpdate(id, payload, { new: true });
        if (!result) {
            throw new ApiError(404, 'Không tìm thấy tiêu chí');
        }

        return {
            success: true,
            message: 'Cập nhật tiêu chí thành công',
            data: result,
        };
    }

    public async deleteNikoCriteria(id: string): Promise<IApiResponse<INikoCriteria>> {
        const ComplimentModel = mongoose.connection.models['Compliments'];
        if (ComplimentModel) {
            const isUsed = await ComplimentModel.findOne({ criteriaId: id });
            if (isUsed) {
                throw new ApiError(400, 'Tiêu chí đang được sử dụng trong lời khen không được xóa');
            }
        }

        const result = await NikoCriteriaModel.findByIdAndDelete(id);
        if (!result) {
            throw new ApiError(404, 'Không tìm thấy tiêu chí');
        }

        return {
            success: true,
            message: 'Xóa tiêu chí thành công',
            data: result,
        };
    }
}

