import { createApi, fetchBaseQuery } from "@reduxjs/toolkit/query/react";
import type { BaseQueryFn, FetchArgs, FetchBaseQueryError } from "@reduxjs/toolkit/query/react";

const rawBaseQuery = fetchBaseQuery({
  baseUrl: import.meta.env.VITE_API_URL || "http://localhost:5857/api/v1",
  prepareHeaders: (headers) => {
    const token = localStorage.getItem("token");
    if (token) {
      headers.set("authorization", `Bearer ${token}`);
    }
    headers.set("Content-Type", "application/json");
    return headers;
  },
  credentials: "include",
});

// Thực tế, để can thiệp vào URL TRƯỚC khi gửi đi mà vẫn dùng fetchBaseQuery:
const baseQueryWithReformatting: BaseQueryFn<string | FetchArgs, unknown, FetchBaseQueryError> = async (
  args,
  api,
  extraOptions,
) => {
  if (typeof args !== "string" && args.params) {
    // Chúng ta sẽ tự serialize params để kiểm soát việc encode
    const { url, params, ...rest } = args;
    const queryParams = new URLSearchParams();

    Object.entries(params).forEach(([key, value]) => {
      if (value !== undefined && value !== null) {
        queryParams.append(key, String(value));
      }
    });

    // Chuyển đối %3A ngược lại thành : (định dạng ISO Date)
    const queryString = queryParams.toString().replace(/%3A/g, ":");
    const newUrl = `${url}${url.includes("?") ? "&" : "?"}${queryString}`;

    return rawBaseQuery({ ...rest, url: newUrl }, api, extraOptions);
  }

  return rawBaseQuery(args, api, extraOptions);
};

let refreshPromise: Promise<string | null> | null = null;

const baseQueryWithReauth: BaseQueryFn<string | FetchArgs, unknown, FetchBaseQueryError> = async (
  args,
  api,
  extraOptions,
) => {
  let result = await baseQueryWithReformatting(args, api, extraOptions);

  if (result.error && result.error.status === 401) {
    // Nếu chưa có tiến trình refresh nào, tạo mới
    if (!refreshPromise) {
      refreshPromise = (async () => {
        try {
          const refreshResult: any = await rawBaseQuery(
            {
              url: "/auth/refresh-token",
              method: "POST",
            },
            api,
            extraOptions,
          );

          if (refreshResult.data) {
            const accessToken = refreshResult.data.data.accessToken;
            localStorage.setItem("token", accessToken);
            return accessToken;
          } else {
            localStorage.removeItem("token");
            window.location.href = "/login";
            return null;
          }
        } catch (error) {
          localStorage.removeItem("token");
          window.location.href = "/login";
          return null;
        } finally {
          refreshPromise = null;
        }
      })();
    }

    const token = await refreshPromise;

    if (token) {
      // Thử lại request ban đầu với token mới
      result = await baseQueryWithReformatting(args, api, extraOptions);
    }
  }

  return result;
};

export const baseApi = createApi({
  reducerPath: "api",
  baseQuery: baseQueryWithReauth,
  tagTypes: [
    "Auth",
    "Account",
    "Employee",
    "Department",
    "Position",
    "Role",
    "ShiftType",
    "Shift",
    "Schedule",
    "Attendance",
    "LeaveRequest",
    "LeaveType",
    "OKR",
    "Contract",
    "Payroll",
    "GlobalSetting",
    "SystemLog",
    "KeyResultLink",
    "IncomeType",
    "DeductionType",
    "NikoEmotion",
    "Permission",
    "AccountRole",
    "Checkins",
    "CheckinSchedules",
  ],
  endpoints: () => ({}),
});

