import { Server, Socket } from 'socket.io';
import logger from '@common/utils/logger';
import { FE_SERVER } from '@common/config/environment';
import { IAccounts } from '@common/interfaces/accounts.interface';
import { authenticationSocket } from '@common/middlewares/authen.middleware';
import http from 'http';


class SocketService {
    private server?: Server;

    public setup(port: number): void {
        const serverHttp = http.createServer();
        const feURLs = FE_SERVER?.split(',').map((h) => h.trim()) || undefined;
        this.server = new Server(serverHttp, {
            cors: {
                origin: feURLs || 'http://localhost:5801',
                methods: ['GET', 'POST'],
            },
        });
        this.server.use(authenticationSocket);
        this.handleConnection(this.server);

        serverHttp.listen(port, () => {
            logger.info(`Socket.io server running on port ${port}`);
        });
    }

    private handleConnection(server: Server) {
        server.on('connection', (socket: Socket) => {
            logger.info(`[SOCKET] Client connected: ${socket.id} (User: ${socket.data.user?._id || 'unknown'})`);

            socket.on('connect_error', async (err) => {
                logger.error(`[SOCKET] Connect error for ${socket.id}:`, err);
            });

            socket.on('disconnect', async (reason) => {
                logger.debug(
                    `[SOCKET] Client disconnected: ${socket.id}, reason: ${reason}, user: ${socket.data.user?._id || 'unknown'}`
                );
            });
        });
    }

    public sendNotification(accountId: string, event: string, data: unknown): void {
        if (!this.server) {
            logger.error('Socket.io not initialized');
            return;
        }

        this.server.to(this.getRoomName(accountId)).emit(event, data);
    }

    public async register(socket: Socket, user: IAccounts): Promise<void> {
        return socket.join(this.getRoomName(String(user._id)));
    }

    public getRoomName(employeeId: string): string {
        return `u_${employeeId}`;
    }

    public async close(): Promise<void> {
        if (this.server) {
            logger.info('Closing Socket.io server...');
