import { baseApi } from "../../../stores/baseApi";

export const attendanceApi = baseApi.injectEndpoints({
  endpoints: (builder) => ({
    getAttendances: builder.query<any, any>({
      query: (params) => ({
        url: "/attendances",
        params,
      }),
      providesTags: (result) =>
        result?.data
          ? [
              ...result.data.map(({ _id }: any) => ({ type: "Attendance" as const, id: _id })),
              { type: "Attendance", id: "LIST" },
            ]
          : [{ type: "Attendance", id: "LIST" }],
    }),
    getAttendanceDetail: builder.query<any, string>({
      query: (id) => `/attendances/${id}`,
      providesTags: (result, error, id) => [{ type: "Attendance", id }],
    }),
    createAttendance: builder.mutation<any, any>({
      query: (body) => ({
        url: "/attendances",
        method: "POST",
        body,
      }),
      invalidatesTags: [{ type: "Attendance", id: "LIST" }],
    }),
    updateAttendance: builder.mutation<any, { _id: string; [key: string]: any }>({
      query: ({ _id, ...body }) => ({
        url: `/attendances/${_id}`,
        method: "PATCH",
        body,
      }),
      invalidatesTags: (result, error, { _id }) => [
        { type: "Attendance", id: _id },
        { type: "Attendance", id: "LIST" },
      ],
    }),
    deleteAttendance: builder.mutation<any, string>({
      query: (id) => ({
        url: `/attendances/${id}`,
        method: "DELETE",
      }),
      invalidatesTags: [{ type: "Attendance", id: "LIST" }],
    }),
    mobileAttendance: builder.mutation<any, { encryptedData: string }>({
      query: (body) => ({
        url: "/attendances/create-fe",
        method: "POST",
        body,
        // Chấp nhận cả phản hồi không phải JSON (text/empty) để tránh lỗi parse
        responseHandler: async (response) => {
          if (response.status === 200 || response.status === 201) {
            const text = await response.text();
            try {
              return JSON.parse(text);
            } catch (e) {
              return { success: true, message: text };
            }
          }
          return response.json();
        },
      }),
      invalidatesTags: [{ type: "Attendance", id: "LIST" }],
    }),
  }),
  overrideExisting: false,
});

export const {
  useGetAttendancesQuery,
  useGetAttendanceDetailQuery,
  useCreateAttendanceMutation,
  useUpdateAttendanceMutation,
  useDeleteAttendanceMutation,
  useMobileAttendanceMutation,
} = attendanceApi;

