import ioredis, { Redis } from 'ioredis';
import logger from '@common/utils/logger';
import { REDIS_HOST, REDIS_PORT } from '@config/environment';


export class RedisAdapter {
    private static client: Redis;

    static async getClient(): Promise<Redis> {
        if (!RedisAdapter.client) {
            await RedisAdapter.connect();
        }
        return RedisAdapter.client;
    }

    static async connect(): Promise<Redis> {
        const redisUri = `redis://${process.env.REDIS_PASSWORD ? `:${process.env.REDIS_PASSWORD}@` : ""}${REDIS_HOST}:${REDIS_PORT}`;

        const tmp = new ioredis(redisUri, {
            lazyConnect: true,
            maxRetriesPerRequest: 10,
            retryStrategy: (times) => {
                const delay = Math.min(times * 1000, 2000);
                if (times < 5) {
                    return delay;
                }
